{
  "$schema": "http://json-schema.org/draft-07/schema#",
  "$id": "https://k3rn.labs/schemas/analysis-input-v1.0.json",
  "title": "K3RN.LABS Analysis Input Schema v1.0",
  "description": "Canonical JSON Schema for idea analysis input - strict validation",
  "type": "object",
  "required": ["meta", "idea", "inputs"],
  "additionalProperties": false,
  "properties": {
    "meta": {
      "type": "object",
      "required": ["schema_version", "request_id", "timestamp", "language"],
      "additionalProperties": false,
      "properties": {
        "schema_version": {
          "type": "string",
          "const": "1.0",
          "description": "Schema version - must be exactly '1.0'"
        },
        "request_id": {
          "type": "string",
          "format": "uuid",
          "description": "Unique request identifier (UUID v4)"
        },
        "timestamp": {
          "type": "string",
          "format": "date-time",
          "description": "Request timestamp (ISO 8601)"
        },
        "language": {
          "type": "string",
          "pattern": "^[a-z]{2}$",
          "description": "Language code (ISO 639-1, e.g., 'fr', 'en')"
        }
      }
    },
    "idea": {
      "type": "object",
      "required": ["idea_id", "state"],
      "additionalProperties": false,
      "properties": {
        "idea_id": {
          "type": "string",
          "format": "uuid",
          "description": "Idea unique identifier"
        },
        "state": {
          "type": "string",
          "enum": ["CAPTURED", "ANALYZED", "ENRICHED"],
          "description": "Current idea state"
        }
      }
    },
    "inputs": {
      "type": "object",
      "additionalProperties": false,
      "properties": {
        "text": {
          "type": "object",
          "required": ["content", "source", "length"],
          "additionalProperties": false,
          "properties": {
            "content": {
              "type": "string",
              "minLength": 10,
              "maxLength": 5000,
              "description": "Text content (10-5000 characters)"
            },
            "source": {
              "type": "string",
              "enum": ["typed", "voice_transcript", "imported"],
              "description": "Text source type"
            },
            "length": {
              "type": "integer",
              "minimum": 10,
              "maximum": 5000,
              "description": "Text length in characters"
            }
          }
        },
        "links": {
          "type": "array",
          "maxItems": 5,
          "items": {
            "$ref": "#/definitions/link"
          },
          "description": "External links (max 5)"
        },
        "files": {
          "type": "array",
          "maxItems": 3,
          "items": {
            "$ref": "#/definitions/file"
          },
          "description": "Attached files metadata (max 3)"
        }
      }
    },
    "context": {
      "type": "object",
      "required": ["user_id"],
      "additionalProperties": false,
      "properties": {
        "user_id": {
          "type": "string",
          "format": "uuid",
          "description": "User unique identifier"
        },
        "experience_level": {
          "type": "string",
          "enum": ["BEGINNER", "INTERMEDIATE", "ADVANCED"],
          "description": "User experience level (optional)"
        },
        "previous_ideas_count": {
          "type": "integer",
          "minimum": 0,
          "description": "Number of previously analyzed ideas"
        }
      }
    }
  },
  "definitions": {
    "link": {
      "type": "object",
      "required": ["url", "type"],
      "additionalProperties": false,
      "properties": {
        "url": {
          "type": "string",
          "format": "uri",
          "description": "Valid URL (http/https)"
        },
        "type": {
          "type": "string",
          "enum": ["web", "social", "doc"],
          "description": "Link type"
        }
      }
    },
    "file": {
      "type": "object",
      "required": ["file_id", "type", "size_kb"],
      "additionalProperties": false,
      "properties": {
        "file_id": {
          "type": "string",
          "format": "uuid",
          "description": "File unique identifier"
        },
        "type": {
          "type": "string",
          "enum": ["pdf", "image", "text"],
          "description": "File type"
        },
        "size_kb": {
          "type": "integer",
          "minimum": 1,
          "maximum": 10240,
          "description": "File size in KB (max 10MB)"
        }
      }
    }
  }
}

