     8→// System Prompt synthesizing the "Committee of Experts"
     9→const getSystemPrompt = (lang: string) => {
    10→  const languageName = lang === 'en' ? 'English' : 'French (Français)';
    11→
    12→  return `
    13→You are the **K3RN.LABS Expert Committee**, a collective intelligence engine composed of World-Class Principals.
    14→Your mission is to analyze startup ideas/projects with extreme rigor, institutional sobriety, and high density.
    15→
    16→**THE COMMITTEE MEMBERS:**
    17→1. **Product Strategist**: Focuses on value proposition, scope, and product principles. (Ref: EXP_PRODUCT_STRATEGIST_01)
    18→2. **Business Model Analyst**: Focuses on viability, revenue streams, and unit economics. (Ref: EXP_BUSINESS_MODEL_01)
    19→3. **Technical Architect**: Focuses on feasibility, scalability, and stack choices. (Ref: EXP_TECH_ARCHITECT_01)
    20→
    21→**TONE & STYLE:**
    22→- **Institutional & Sober**: No hype, no marketing fluff, no emojis.
    23→- **High Density**: Maximum information in minimum words.
    24→- **Direct**: Critique without sugar-coating.
    25→- **Language**: ${languageName} (Strictly output in this language).
    26→
    27→**OUTPUT FORMAT (JSON):**
    28→You must return a valid JSON object with the following structure:
    29→{
    30→  "viabilityScore": number, // 0-100. Be strict. <70 is common. >90 is rare.
    31→  "classification": string, // One of: "REJECT", "INCUBATE", "ACCELERATE"
    32→  "summary": string, // A 1-sentence synthesis of the verdict.
    33→  "experts": [
    34→    {
    35→      "role": "Product Strategist",
    36→      "status": "VALIDATED" | "WARNING" | "CRITICAL",
    37→      "analysis": "Specific critique or validation point..."
    38→    },
    39→    {
    40→      "role": "Business Model Analyst",
    41→      "status": "VALIDATED" | "WARNING" | "CRITICAL",
    42→      "analysis": "Specific critique or validation point..."
    43→    },
    44→    {
    45→      "role": "Technical Architect",
    46→      "status": "VALIDATED" | "WARNING" | "CRITICAL",
    47→      "analysis": "Specific critique or validation point..."
    48→    }
    49→  ],
    50→  "nextSteps": string[] // 3 concrete, actionable steps.
    51→}
    52→`;
    53→};
    54→
    55→export async function POST(req: Request) {
    56→  try {
    57→    const body = await req.json();
    58→    const { text, files, links, lang = 'fr' } = body;
    59→
    60→    // Construct the user message based on available inputs
    61→    let userContent = `Here is the project idea to analyze:\n\n**Description:**\n${text}\n`;
    62→
    63→    if (links && links.length > 0) {
    64→      userContent += `\n**Links:**\n${links.join('\n')}\n`;
    65→    }
    66→
    67→    if (files && files.length > 0) {
    68→      userContent += `\n**Files Attached:**\n${files.map((f: any) => `${f.name} (${f.type})`).join(', ')}\n`;
    69→    }
    70→
    71→    const completion = await openai.chat.completions.create({
    72→      model: "gpt-4o", // Or gpt-4-turbo if preferred
    73→      messages: [
    74→        { role: "system", content: getSystemPrompt(lang) },
    75→        { role: "user", content: userContent },
    76→      ],
    77→      response_format: { type: "json_object" },
    78→      temperature: 0.2, // Low temperature for consistent, analytical results
    79→    });
    80→
    81→    const result = JSON.parse(completion.choices[0].message.content || "{}");
    82→    return NextResponse.json(result);
    83→
    84→  } catch (error: any) {
    85→    console.error("Analysis API Error:", error);
    86→
    87→    // Handle OpenAI Quota Exceeded specifically
    88→    if (error?.status === 429 || error?.code === 'insufficient_quota') {
    89→      return NextResponse.json(
    90→        { error: "QUOTA_EXCEEDED", details: "OpenAI API quota exceeded. Switching to demo mode." },
    91→        { status: 429 }
    92→      );
    93→    }
    94→
    95→    return NextResponse.json(
    96→      { error: "Analysis failed", details: error.message },
    97→      { status: 500 }
    98→    );
    99→  }
   100→}
