     5→import { useRouter } from "next/navigation";
     6→import { createClient } from "@/lib/supabase/client";
     7→import { User, Session } from "@supabase/supabase-js";
     8→
     9→interface AuthContextType {
    10→    user: User | null;
    11→    session: Session | null;
    12→    isLoading: boolean;
    13→    signIn: (email: string, password?: string) => Promise<void>;
    14→    signUp: (email: string, password?: string) => Promise<void>;
    15→    signOut: () => Promise<void>;
    16→    showAuthModal: boolean;
    17→    setShowAuthModal: (show: boolean) => void;
    18→}
    19→
    20→const AuthContext = createContext<AuthContextType | undefined>(undefined);
    21→
    22→export function AuthProvider({ children }: { children: React.ReactNode }) {
    23→    const [user, setUser] = useState<User | null>(null);
    24→    const [session, setSession] = useState<Session | null>(null);
    25→    const [isLoading, setIsLoading] = useState(true);
    26→    const [showAuthModal, setShowAuthModal] = useState(false);
    27→    const router = useRouter();
    28→    const supabase = createClient();
    29→
    30→    // Initialize Auth State
    31→    useEffect(() => {
    32→        const initAuth = async () => {
    33→            try {
    34→                const { data: { session } } = await supabase.auth.getSession();
    35→                setSession(session);
    36→                setUser(session?.user ?? null);
    37→            } catch (error) {
    38→                console.error("Auth init error:", error);
    39→            } finally {
    40→                setIsLoading(false);
    41→            }
    42→        };
    43→
    44→        const { data: { subscription } } = supabase.auth.onAuthStateChange((_event, session) => {
    45→            setSession(session);
    46→            setUser(session?.user ?? null);
    47→            setIsLoading(false);
    48→
    49→            if (session) {
    50→                // Close modal on successful sign in if open
    51→                setShowAuthModal(false);
    52→            }
    53→        });
    54→
    55→        initAuth();
    56→
    57→        return () => subscription.unsubscribe();
    58→    }, [supabase]);
    59→
    60→    const signIn = async (email: string, password?: string) => {
    61→        try {
    62→            setIsLoading(true);
    63→
    64→            if (password) {
    65→                // Email + Password
    66→                const { error } = await supabase.auth.signInWithPassword({
    67→                    email,
    68→                    password
    69→                });
    70→                if (error) throw error;
    71→                toast.success("Bon retour", { description: "Connexion réussie." });
    72→            } else {
    73→                // Magic Link (Fallback)
    74→                const { error } = await supabase.auth.signInWithOtp({
    75→                    email,
    76→                    options: {
    77→                        emailRedirectTo: `${window.location.origin}/auth/callback`,
    78→                    },
    79→                });
    80→                if (error) throw error;
    81→                toast.success("Lien de connexion envoyé", { description: "Vérifiez votre boîte mail." });
    82→            }
    83→            setShowAuthModal(false);
    84→        } catch (error: any) {
    85→            console.error("Login error:", error);
    86→            toast.error("Erreur de connexion", { description: error.message || "Identifiants invalides." });
    87→        } finally {
    88→            setIsLoading(false);
    89→        }
    90→    };
    91→
    92→    const signUp = async (email: string, password?: string) => {
    93→        try {
    94→            setIsLoading(true);
    95→
    96→            if (password) {
    97→                const { error } = await supabase.auth.signUp({
    98→                    email,
    99→                    password,
   100→                    options: {
   101→                        emailRedirectTo: `${window.location.origin}/auth/callback`,
   102→                    }
   103→                });
   104→                if (error) throw error;
   105→                toast.success("Compte créé", { description: "Vérifiez votre email pour confirmer." });
   106→            } else {
   107→                const { error } = await supabase.auth.signInWithOtp({
   108→                    email,
   109→                    options: {
   110→                        emailRedirectTo: `${window.location.origin}/auth/callback`,
   111→                    }
   112→                });
   113→                if (error) throw error;
   114→                toast.success("Vérifiez votre email", { description: "Un lien de connexion a été envoyé." });
   115→            }
   116→            setShowAuthModal(false);
   117→        } catch (error: any) {
   118→            console.error("Signup error:", error);
   119→            toast.error("Erreur d'inscription", { description: error.message });
   120→        } finally {
   121→            setIsLoading(false);
   122→        }
   123→    };
   124→
   125→    const signOut = async () => {
   126→        try {
   127→            setIsLoading(true);
   128→            await supabase.auth.signOut();
   129→            toast.info("Déconnecté");
   130→            router.push("/");
   131→            router.refresh();
   132→        } catch (error) {
   133→            console.error("SignOut error:", error);
   134→        } finally {
   135→            setIsLoading(false);
   136→        }
   137→    };
   138→
   139→    return (
   140→        <AuthContext.Provider value={{
   141→            user,
   142→            session,
   143→            isLoading,
   144→            signIn,
   145→            signUp,
   146→            signOut,
   147→            showAuthModal,
   148→            setShowAuthModal
   149→        }}>
   150→            {children}
   151→        </AuthContext.Provider>
   152→    );
   153→}
   154→
   155→export function useAuth() {
   156→    const context = useContext(AuthContext);
   157→    if (context === undefined) {
   158→        throw new Error("useAuth must be used within an AuthProvider");
   159→    }
   160→    return context;
   161→}
