import { NextResponse } from 'next/server';
import OpenAI from 'openai';

const openai = new OpenAI({
  apiKey: process.env.OPENAI_API_KEY,
});

// System Prompt synthesizing the "Committee of Experts"
const getSystemPrompt = (lang: string) => {
  const languageName = lang === 'en' ? 'English' : 'French (Français)';

  return `
You are the **K3RN.LABS Expert Committee**, a collective intelligence engine composed of World-Class Principals.
Your mission is to analyze startup ideas/projects with extreme rigor, institutional sobriety, and high density.

**THE COMMITTEE MEMBERS:**
1. **Product Strategist**: Focuses on value proposition, scope, and product principles. (Ref: EXP_PRODUCT_STRATEGIST_01)
2. **Business Model Analyst**: Focuses on viability, revenue streams, and unit economics. (Ref: EXP_BUSINESS_MODEL_01)
3. **Technical Architect**: Focuses on feasibility, scalability, and stack choices. (Ref: EXP_TECH_ARCHITECT_01)

**TONE & STYLE:**
- **Institutional & Sober**: No hype, no marketing fluff, no emojis.
- **High Density**: Maximum information in minimum words.
- **Direct**: Critique without sugar-coating.
- **Language**: ${languageName} (Strictly output in this language).

**OUTPUT FORMAT (JSON):**
You must return a valid JSON object with the following structure:
{
  "viabilityScore": number, // 0-100. Be strict. <70 is common. >90 is rare.
  "classification": string, // One of: "REJECT", "INCUBATE", "ACCELERATE"
  "summary": string, // A 1-sentence synthesis of the verdict.
  "experts": [
    {
      "role": "Product Strategist",
      "status": "VALIDATED" | "WARNING" | "CRITICAL",
      "analysis": "Specific critique or validation point..."
    },
    {
      "role": "Business Model Analyst",
      "status": "VALIDATED" | "WARNING" | "CRITICAL",
      "analysis": "Specific critique or validation point..."
    },
    {
      "role": "Technical Architect",
      "status": "VALIDATED" | "WARNING" | "CRITICAL",
      "analysis": "Specific critique or validation point..."
    }
  ],
  "nextSteps": string[] // 3 concrete, actionable steps.
}
`;
};

export async function POST(req: Request) {
  try {
    const body = await req.json();
    const { text, files, links, lang = 'fr' } = body;

    // Construct the user message based on available inputs
    let userContent = `Here is the project idea to analyze:\n\n**Description:**\n${text}\n`;

    if (links && links.length > 0) {
      userContent += `\n**Links:**\n${links.join('\n')}\n`;
    }

    if (files && files.length > 0) {
      userContent += `\n**Files Attached:**\n${files.map((f: any) => `${f.name} (${f.type})`).join(', ')}\n`;
    }

    const completion = await openai.chat.completions.create({
      model: "gpt-4o", // Or gpt-4-turbo if preferred
      messages: [
        { role: "system", content: getSystemPrompt(lang) },
        { role: "user", content: userContent },
      ],
      response_format: { type: "json_object" },
      temperature: 0.2, // Low temperature for consistent, analytical results
    });

    const result = JSON.parse(completion.choices[0].message.content || "{}");
    return NextResponse.json(result);

  } catch (error: any) {
    console.error("Analysis API Error:", error);

    // Handle OpenAI Quota Exceeded specifically
    if (error?.status === 429 || error?.code === 'insufficient_quota') {
      return NextResponse.json(
        { error: "QUOTA_EXCEEDED", details: "OpenAI API quota exceeded. Switching to demo mode." },
        { status: 429 }
      );
    }

    return NextResponse.json(
      { error: "Analysis failed", details: error.message },
      { status: 500 }
    );
  }
}

