/**
 * K3RN.LABS — Types TypeScript pour l'analyse d'idées
 * Alignés strictement sur les JSON Schemas canoniques v1.0
 */

import type { AnalysisAxis } from './constants';

// ═══════════════════════════════════════════════════════════════════
// INPUT TYPES (analysis-input-v1.0.schema.json)
// ═══════════════════════════════════════════════════════════════════

export interface AnalysisInputMeta {
  schema_version: '1.0';
  request_id: string;
  timestamp: string;
  language: string;
}

export interface AnalysisInputIdea {
  idea_id: string;
  state: 'CAPTURED' | 'ANALYZED' | 'ENRICHED';
}

export interface AnalysisInputText {
  content: string;
  source: 'typed' | 'voice_transcript' | 'imported';
  length: number;
}

export interface AnalysisInputLink {
  url: string;
  type: 'web' | 'social' | 'doc';
}

export interface AnalysisInputFile {
  file_id: string;
  type: 'pdf' | 'image' | 'text';
  size_kb: number;
}

export interface AnalysisInputs {
  text?: AnalysisInputText;
  links?: AnalysisInputLink[];
  files?: AnalysisInputFile[];
}

export interface AnalysisInputContext {
  user_id: string;
  experience_level?: 'BEGINNER' | 'INTERMEDIATE' | 'ADVANCED';
  previous_ideas_count?: number;
}

export interface AnalysisInput {
  meta: AnalysisInputMeta;
  idea: AnalysisInputIdea;
  inputs: AnalysisInputs;
  context?: AnalysisInputContext;
}

// ═══════════════════════════════════════════════════════════════════
// OUTPUT TYPES (analysis-output-v1.0.schema.json)
// ═══════════════════════════════════════════════════════════════════

export interface AnalysisOutputMeta {
  schema_version: '1.0';
  analysis_id: string;
  timestamp: string;
  orchestrator_version: string;
  model: string;
}

export interface AnalysisOutputIdea {
  idea_id: string;
  title: string;
  raw_summary: string;
  inputs_used: ('text' | 'voice' | 'link' | 'file')[];
}

export interface AxisAnalysis {
  score: number;
  justification: string;
  blocking_gap: boolean;
}

export interface AnalysisAxes {
  problem: AxisAnalysis;
  market: AxisAnalysis;
  differentiation: AxisAnalysis;
  feasibility: AxisAnalysis;
  business: AxisAnalysis;
  founder_fit: AxisAnalysis;
}

export interface AnalysisScores {
  global_score: number;
  weights: Record<AnalysisAxis, number>;
}

export interface AnalysisDecision {
  recommendation: 'GO' | 'EXPLORE' | 'PARK' | 'KILL';
  confidence_level: 'LOW' | 'MEDIUM' | 'HIGH';
  summary: string;
}

export interface AnalysisRisk {
  axis: AnalysisAxis;
  description: string;
  severity: 'LOW' | 'MEDIUM' | 'HIGH';
}

export interface AnalysisLever {
  axis: AnalysisAxis;
  action: string;
  expected_impact: 'LOW' | 'MEDIUM' | 'HIGH';
}

export interface AnalysisEnrichment {
  required: boolean;
  trigger_axes: AnalysisAxis[];
  max_questions: number;
}

export interface LabOrientation {
  recommended: boolean;
  lab: 'DISCOVERY' | 'MARKET' | 'STRATEGY' | 'TECH' | 'BUSINESS' | 'NONE';
  reason: string;
}

export interface AnalysisOutput {
  meta: AnalysisOutputMeta;
  idea: AnalysisOutputIdea;
  analysis: AnalysisAxes;
  scores: AnalysisScores;
  decision: AnalysisDecision;
  risks: AnalysisRisk[];
  levers: AnalysisLever[];
  enrichment: AnalysisEnrichment;
  lab_orientation: LabOrientation;
}

// ═══════════════════════════════════════════════════════════════════
// ENRICHMENT TYPES (Contrat Questions Guidées v1.1 + Widget Schema v1.0)
// ═══════════════════════════════════════════════════════════════════

export interface QuestionOption {
  id: string;
  label: string;
  value: string;
  score_adjustment: number;
}

export interface QuestionExpectedImpact {
  axis: AnalysisAxis;
  min_adjustment: number;
  max_adjustment: number;
}

export interface EnrichmentQuestion {
  question_id: string;
  axis: AnalysisAxis;
  type: 'single_select' | 'multi_select' | 'range' | 'ranking';
  prompt: string;
  options: QuestionOption[];
  allow_skip: boolean;
  timeout_seconds: number;
  expected_impact: QuestionExpectedImpact;
}

export interface EnrichmentResponse {
  question_id: string;
  status: 'completed' | 'skipped' | 'skipped_timeout';
  selected_option_ids?: string[];
  response_time_seconds?: number;
}

export interface EnrichmentRequest {
  idea_id: string;
  analysis_id: string;
  analysis: AnalysisAxes;
  scores: AnalysisScores;
  decision: AnalysisDecision;
}

export interface EnrichmentResult {
  enrichment_id: string;
  idea_id: string;
  timestamp: string;
  questions: EnrichmentQuestion[];
  trigger_axes: AnalysisAxis[];
}

export interface EnrichmentSubmission {
  enrichment_id: string;
  idea_id: string;
  responses: EnrichmentResponse[];
}

export interface EnrichmentRecalculation {
  enrichment_id: string;
  idea_id: string;
  timestamp: string;
  scores_before: Record<string, number>;
  scores_after: Record<string, number>;
  decision_before: string;
  decision_after: string;
  confidence_before: string;
  confidence_after: string;
  adjustments: Array<{
    axis: AnalysisAxis;
    question_id: string;
    adjustment: number;
  }>;
}

// ═══════════════════════════════════════════════════════════════════
// API ERROR TYPES
// ═══════════════════════════════════════════════════════════════════

export interface ApiError {
  error: {
    code: string;
    message: string;
    details?: unknown;
  };
}

