/**
 * K3RN.LABS — Validateurs Zod pour l'analyse d'idées
 * Alignés strictement sur les JSON Schemas canoniques v1.0
 */

import { z } from 'zod';
import {
  SCHEMA_VERSION,
  ANALYSIS_AXES,
  CANONICAL_WEIGHTS,
  SCORE_RANGE,
} from './constants';

// ═══════════════════════════════════════════════════════════════════
// INPUT VALIDATORS
// ═══════════════════════════════════════════════════════════════════

const inputMetaSchema = z.object({
  schema_version: z.literal(SCHEMA_VERSION),
  request_id: z.string().min(1),
  timestamp: z.string().datetime(),
  language: z.string().regex(/^[a-z]{2}$/),
});

const inputIdeaSchema = z.object({
  idea_id: z.string().min(1),
  state: z.enum(['CAPTURED', 'ANALYZED', 'ENRICHED']),
});

const inputTextSchema = z.object({
  content: z.string().min(10).max(5000),
  source: z.enum(['typed', 'voice_transcript', 'imported']),
  length: z.number().int().min(10).max(5000),
});

const inputLinkSchema = z.object({
  url: z.string().url(),
  type: z.enum(['web', 'social', 'doc']),
});

const inputFileSchema = z.object({
  file_id: z.string().min(1),
  type: z.enum(['pdf', 'image', 'text']),
  size_kb: z.number().int().min(1).max(10240),
});

const inputsSchema = z.object({
  text: inputTextSchema.optional(),
  links: z.array(inputLinkSchema).max(5).optional(),
  files: z.array(inputFileSchema).max(3).optional(),
});

const inputContextSchema = z.object({
  user_id: z.string().min(1),
  experience_level: z.enum(['BEGINNER', 'INTERMEDIATE', 'ADVANCED']).optional(),
  previous_ideas_count: z.number().int().min(0).optional(),
});

export const analysisInputSchema = z.object({
  meta: inputMetaSchema,
  idea: inputIdeaSchema,
  inputs: inputsSchema,
  context: inputContextSchema.optional(),
});

// ═══════════════════════════════════════════════════════════════════
// OUTPUT VALIDATORS
// ═══════════════════════════════════════════════════════════════════

const outputMetaSchema = z.object({
  schema_version: z.literal(SCHEMA_VERSION),
  analysis_id: z.string().min(1),
  timestamp: z.string().datetime(),
  orchestrator_version: z.string().regex(/^v\d+\.\d+$/),
  model: z.string().min(1),
});

const outputIdeaSchema = z.object({
  idea_id: z.string().min(1),
  title: z.string().min(3).max(200),
  raw_summary: z.string().min(10).max(500),
  inputs_used: z
    .array(z.enum(['text', 'voice', 'link', 'file']))
    .min(1),
});

const axisAnalysisSchema = z.object({
  score: z.number().int().min(SCORE_RANGE.MIN).max(SCORE_RANGE.MAX),
  justification: z.string().min(20).max(300),
  blocking_gap: z.boolean(),
});

const analysisAxesSchema = z.object({
  problem: axisAnalysisSchema,
  market: axisAnalysisSchema,
  differentiation: axisAnalysisSchema,
  feasibility: axisAnalysisSchema,
  business: axisAnalysisSchema,
  founder_fit: axisAnalysisSchema,
});

const weightsSchema = z.object({
  problem: z.literal(CANONICAL_WEIGHTS.problem),
  market: z.literal(CANONICAL_WEIGHTS.market),
  differentiation: z.literal(CANONICAL_WEIGHTS.differentiation),
  feasibility: z.literal(CANONICAL_WEIGHTS.feasibility),
  business: z.literal(CANONICAL_WEIGHTS.business),
  founder_fit: z.literal(CANONICAL_WEIGHTS.founder_fit),
});

const scoresSchema = z.object({
  global_score: z.number().int().min(SCORE_RANGE.MIN).max(SCORE_RANGE.MAX),
  weights: weightsSchema,
});

const decisionSchema = z.object({
  recommendation: z.enum(['GO', 'EXPLORE', 'PARK', 'KILL']),
  confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
  summary: z.string().min(20).max(500),
});

const axisEnum = z.enum(ANALYSIS_AXES as unknown as [string, ...string[]]);

const riskSchema = z.object({
  axis: axisEnum,
  description: z.string().min(10).max(200),
  severity: z.enum(['LOW', 'MEDIUM', 'HIGH']),
});

const leverSchema = z.object({
  axis: axisEnum,
  action: z.string().min(10).max(200),
  expected_impact: z.enum(['LOW', 'MEDIUM', 'HIGH']),
});

const enrichmentSchema = z.object({
  required: z.boolean(),
  trigger_axes: z.array(axisEnum).max(2),
  max_questions: z.number().int().min(0).max(5),
});

const labOrientationSchema = z.object({
  recommended: z.boolean(),
  lab: z.enum(['DISCOVERY', 'MARKET', 'STRATEGY', 'TECH', 'BUSINESS', 'NONE']),
  reason: z.string().min(10).max(200),
});

export const analysisOutputSchema = z.object({
  meta: outputMetaSchema,
  idea: outputIdeaSchema,
  analysis: analysisAxesSchema,
  scores: scoresSchema,
  decision: decisionSchema,
  risks: z.array(riskSchema).max(5),
  levers: z.array(leverSchema).max(3),
  enrichment: enrichmentSchema,
  lab_orientation: labOrientationSchema,
});

// ═══════════════════════════════════════════════════════════════════
// LLM RAW OUTPUT VALIDATOR (sans meta, car ajoutés côté serveur)
// ═══════════════════════════════════════════════════════════════════

export const llmRawOutputSchema = z.object({
  idea: z.object({
    title: z.string().min(3).max(200),
    raw_summary: z.string().min(10).max(500),
  }),
  analysis: analysisAxesSchema,
  decision: z.object({
    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
    summary: z.string().min(20).max(500),
  }),
  risks: z.array(riskSchema).max(5),
  levers: z.array(leverSchema).max(3),
  lab_orientation: z.object({
    recommended: z.boolean(),
    lab: z.enum(['DISCOVERY', 'MARKET', 'STRATEGY', 'TECH', 'BUSINESS', 'NONE']),
    reason: z.string().min(10).max(200),
  }),
});

// ═══════════════════════════════════════════════════════════════════
// ENRICHMENT VALIDATORS (Widget Schema v1.0)
// ═══════════════════════════════════════════════════════════════════

const questionOptionSchema = z.object({
  id: z.string().min(1),
  label: z.string().min(1),
  value: z.string().min(1),
  score_adjustment: z.number().min(-25).max(25),
});

export const enrichmentQuestionSchema = z.object({
  question_id: z.string().min(1),
  axis: axisEnum,
  type: z.enum(['single_select', 'multi_select', 'range', 'ranking']),
  prompt: z.string().min(10).max(200),
  options: z.array(questionOptionSchema).min(2).max(5),
  allow_skip: z.boolean(),
  timeout_seconds: z.number().int().min(1),
  expected_impact: z.object({
    axis: axisEnum,
    min_adjustment: z.number(),
    max_adjustment: z.number(),
  }),
});

export const enrichmentResponseSchema = z.object({
  question_id: z.string().min(1),
  status: z.enum(['completed', 'skipped', 'skipped_timeout']),
  selected_option_ids: z.array(z.string()).optional(),
  response_time_seconds: z.number().min(0).optional(),
});

// ═══════════════════════════════════════════════════════════════════
// VALIDATION HELPERS
// ═══════════════════════════════════════════════════════════════════

export interface ValidationResult<T> {
  valid: boolean;
  data?: T;
  errors?: string[];
}

export function validateAnalysisInput(data: unknown): ValidationResult<z.infer<typeof analysisInputSchema>> {
  const result = analysisInputSchema.safeParse(data);
  if (result.success) {
    return { valid: true, data: result.data };
  }
  return {
    valid: false,
    errors: result.error.issues.map(
      (issue) => `${issue.path.join('.')} ${issue.message}`
    ),
  };
}

export function validateAnalysisOutput(data: unknown): ValidationResult<z.infer<typeof analysisOutputSchema>> {
  const result = analysisOutputSchema.safeParse(data);
  if (result.success) {
    return { valid: true, data: result.data };
  }
  return {
    valid: false,
    errors: result.error.issues.map(
      (issue) => `${issue.path.join('.')} ${issue.message}`
    ),
  };
}

export function validateLlmRawOutput(data: unknown): ValidationResult<z.infer<typeof llmRawOutputSchema>> {
  const result = llmRawOutputSchema.safeParse(data);
  if (result.success) {
    return { valid: true, data: result.data };
  }
  return {
    valid: false,
    errors: result.error.issues.map(
      (issue) => `${issue.path.join('.')} ${issue.message}`
    ),
  };
}

