/**
 * K3RN.LABS — Calcul du score global (formule canonique)
 * Source de vérité : Contrat Canonique Analyse Idée v1.1, Section 4.3
 *
 * Score Global =
 *   (score_problem × 0.20) +
 *   (score_market × 0.20) +
 *   (score_differentiation × 0.15) +
 *   (score_feasibility × 0.15) +
 *   (score_business × 0.20) +
 *   (score_founder_fit × 0.10)
 *
 * Arrondi à l'entier le plus proche, borné [0, 100].
 */

import { CANONICAL_WEIGHTS, ANALYSIS_AXES, SCORE_RANGE, type AnalysisAxis } from './constants';
import type { AnalysisAxes } from './types';

/**
 * Calcule le score global pondéré selon la formule canonique.
 * @param analysis - Les 6 axes avec leurs scores
 * @param weights - Les pondérations (optionnel, utilise les canoniques par défaut)
 * @returns Score global entier dans [0, 100]
 */
export function calculateGlobalScore(
  analysis: AnalysisAxes,
  weights: Record<AnalysisAxis, number> = CANONICAL_WEIGHTS
): number {
  let weightedSum = 0;

  for (const axis of ANALYSIS_AXES) {
    const score = analysis[axis]?.score ?? 0;
    const weight = weights[axis] ?? 0;
    weightedSum += score * weight;
  }

  // Arrondi à l'entier le plus proche
  const rounded = Math.round(weightedSum);

  // Bornage [0, 100]
  return Math.max(SCORE_RANGE.MIN, Math.min(SCORE_RANGE.MAX, rounded));
}

/**
 * Vérifie que le score global fourni correspond à la formule canonique.
 * @returns true si le score fourni est correct
 */
export function verifyGlobalScore(
  analysis: AnalysisAxes,
  providedScore: number,
  weights: Record<AnalysisAxis, number> = CANONICAL_WEIGHTS
): boolean {
  const calculated = calculateGlobalScore(analysis, weights);
  return calculated === providedScore;
}

/**
 * Recalcule le score global après ajustements d'enrichissement.
 * @param currentAnalysis - Axes actuels
 * @param adjustments - Map axe → ajustement de score
 * @returns Nouveau score global et nouveaux scores par axe
 */
export function recalculateAfterEnrichment(
  currentAnalysis: AnalysisAxes,
  adjustments: Map<AnalysisAxis, number>
): { globalScore: number; updatedAnalysis: AnalysisAxes } {
  // Deep copy
  const updatedAnalysis: AnalysisAxes = JSON.parse(JSON.stringify(currentAnalysis));

  for (const [axis, adjustment] of adjustments) {
    const currentScore = updatedAnalysis[axis].score;
    // score_enrichi = max(0, min(100, score_initial + ajustement))
    updatedAnalysis[axis].score = Math.max(
      SCORE_RANGE.MIN,
      Math.min(SCORE_RANGE.MAX, currentScore + adjustment)
    );
  }

  const globalScore = calculateGlobalScore(updatedAnalysis);

  return { globalScore, updatedAnalysis };
}

