/**
 * K3RN.LABS — Logique de décision recommandée
 * Source de vérité : Contrat Canonique Analyse Idée v1.1, Section 5.1
 *
 * Ordre de priorité strict :
 * 1. KILL (la plus restrictive)
 * 2. PARK
 * 3. EXPLORE
 * 4. GO (la moins restrictive)
 */

import { DECISION_THRESHOLDS, CRITICAL_AXES, type AnalysisAxis } from './constants';
import type { AnalysisAxes, AnalysisDecision } from './types';

type Decision = 'GO' | 'EXPLORE' | 'PARK' | 'KILL';
type ConfidenceLevel = 'LOW' | 'MEDIUM' | 'HIGH';

interface DecisionResult {
  recommendation: Decision;
  reasons: string[];
}

/**
 * Détermine la décision recommandée selon les règles canoniques.
 *
 * Règle 1 — KILL : score < 30 OU blocking_gap HIGH OU problem < 20
 * Règle 2 — PARK : score [30,50[ ET aucun blocking_gap HIGH ET axes critiques >= 25
 * Règle 3 — EXPLORE : score [50,70[ OU (score >= 70 ET confidence LOW)
 * Règle 4 — GO : score >= 70 ET confidence >= MEDIUM ET aucun blocking_gap ET axes critiques >= 50
 *
 * En cas de conflit, la règle la plus restrictive prévaut.
 */
export function determineDecision(
  globalScore: number,
  analysis: AnalysisAxes,
  confidenceLevel: ConfidenceLevel
): DecisionResult {
  // ─── Règle 1 : KILL ──────────────────────────────────────────
  const killReasons: string[] = [];

  if (globalScore < DECISION_THRESHOLDS.KILL_SCORE) {
    killReasons.push(
      `Score global (${globalScore}) < ${DECISION_THRESHOLDS.KILL_SCORE}`
    );
  }

  // Vérifier blocking_gap HIGH (au moins 1 axe avec blocking_gap = true)
  const blockingAxes = getBlockingGapAxes(analysis);
  if (blockingAxes.length > 0) {
    killReasons.push(
      `Blocking gap détecté sur : ${blockingAxes.join(', ')}`
    );
  }

  if (analysis.problem.score < DECISION_THRESHOLDS.KILL_PROBLEM_MIN) {
    killReasons.push(
      `Score Problème (${analysis.problem.score}) < ${DECISION_THRESHOLDS.KILL_PROBLEM_MIN}`
    );
  }

  if (killReasons.length > 0) {
    return { recommendation: 'KILL', reasons: killReasons };
  }

  // ─── Règle 2 : PARK ──────────────────────────────────────────
  if (
    globalScore >= DECISION_THRESHOLDS.PARK_MIN &&
    globalScore < DECISION_THRESHOLDS.PARK_MAX
  ) {
    // Vérifier aucun axe critique < 25
    const weakCriticalAxes = getCriticalAxesBelowThreshold(
      analysis,
      DECISION_THRESHOLDS.PARK_CRITICAL_MIN
    );

    if (weakCriticalAxes.length === 0) {
      return {
        recommendation: 'PARK',
        reasons: [
          `Score global (${globalScore}) dans la plage [${DECISION_THRESHOLDS.PARK_MIN}, ${DECISION_THRESHOLDS.PARK_MAX}[`,
          'Aucun blocking gap ni axe critique sous seuil',
        ],
      };
    }
    // Si axes critiques < 25, on tombe en KILL (conflit → règle la plus restrictive)
    return {
      recommendation: 'KILL',
      reasons: [
        `Score global (${globalScore}) dans plage PARK mais axes critiques faibles : ${weakCriticalAxes.map((a) => `${a.axis}=${a.score}`).join(', ')}`,
      ],
    };
  }

  // ─── Règle 4 : GO (testée avant EXPLORE pour la logique score >= 70) ──
  if (globalScore >= DECISION_THRESHOLDS.GO_MIN) {
    // GO nécessite confidence >= MEDIUM
    if (confidenceLevel === 'LOW') {
      return {
        recommendation: 'EXPLORE',
        reasons: [
          `Score global (${globalScore}) >= ${DECISION_THRESHOLDS.GO_MIN} mais confidence LOW`,
        ],
      };
    }

    // GO nécessite aucun blocking_gap
    if (blockingAxes.length > 0) {
      // Déjà géré par KILL, mais par sécurité
      return {
        recommendation: 'KILL',
        reasons: [`Blocking gap malgré score élevé (${globalScore})`],
      };
    }

    // GO nécessite tous les axes critiques >= 50
    const weakCriticalAxes = getCriticalAxesBelowThreshold(
      analysis,
      DECISION_THRESHOLDS.GO_CRITICAL_MIN
    );
    if (weakCriticalAxes.length > 0) {
      return {
        recommendation: 'EXPLORE',
        reasons: [
          `Score global (${globalScore}) >= ${DECISION_THRESHOLDS.GO_MIN} mais axes critiques faibles : ${weakCriticalAxes.map((a) => `${a.axis}=${a.score}`).join(', ')}`,
        ],
      };
    }

    return {
      recommendation: 'GO',
      reasons: [
        `Score global (${globalScore}) >= ${DECISION_THRESHOLDS.GO_MIN}`,
        `Confidence ${confidenceLevel} >= MEDIUM`,
        'Aucun blocking gap, tous axes critiques >= 50',
      ],
    };
  }

  // ─── Règle 3 : EXPLORE ───────────────────────────────────────
  if (
    globalScore >= DECISION_THRESHOLDS.EXPLORE_MIN &&
    globalScore < DECISION_THRESHOLDS.EXPLORE_MAX
  ) {
    return {
      recommendation: 'EXPLORE',
      reasons: [
        `Score global (${globalScore}) dans la plage [${DECISION_THRESHOLDS.EXPLORE_MIN}, ${DECISION_THRESHOLDS.EXPLORE_MAX}[`,
      ],
    };
  }

  // ─── Fallback : PARK (score < 30 déjà géré par KILL) ─────────
  return {
    recommendation: 'PARK',
    reasons: [`Score global (${globalScore}) — cas résiduel`],
  };
}

// ═══════════════════════════════════════════════════════════════════
// HELPERS
// ═══════════════════════════════════════════════════════════════════

function getBlockingGapAxes(analysis: AnalysisAxes): AnalysisAxis[] {
  const axes: AnalysisAxis[] = [];
  for (const [key, value] of Object.entries(analysis)) {
    if (value.blocking_gap) {
      axes.push(key as AnalysisAxis);
    }
  }
  return axes;
}

function getCriticalAxesBelowThreshold(
  analysis: AnalysisAxes,
  threshold: number
): Array<{ axis: AnalysisAxis; score: number }> {
  const weak: Array<{ axis: AnalysisAxis; score: number }> = [];
  for (const axis of CRITICAL_AXES) {
    if (analysis[axis].score < threshold) {
      weak.push({ axis, score: analysis[axis].score });
    }
  }
  return weak;
}

