// ═══════════════════════════════════════════════════════════════════

export interface PrioritizedAxis {
  axis: AnalysisAxis;
  score: number;
  weight: number;
  priority: number; // (100 - score) × weight
}

/**
 * Priorise les axes à enrichir selon l'algorithme canonique.
 *
 * score_priorite = (100 - score_axe) × pondération_axe
 * Sélectionne les top 2 axes.
 */
export function prioritizeAxes(
  analysis: AnalysisAxes,
  triggers: EnrichmentTrigger[]
): PrioritizedAxis[] {
  // Collecter les axes éligibles (ceux qui ont un trigger)
  const eligibleAxes = new Set<AnalysisAxis>();
  for (const trigger of triggers) {
    if (trigger.axis) {
      eligibleAxes.add(trigger.axis);
    }
  }

  // Si déclencheur 2 (low confidence) sans axe spécifique,
  // prioriser parmi tous les axes avec score < 70
  if (triggers.some((t) => t.type === 'low_confidence_medium_score')) {
    for (const axis of ANALYSIS_AXES) {
      if (analysis[axis].score < 70 && !analysis[axis].blocking_gap) {
        eligibleAxes.add(axis);
      }
    }
  }

  // Calculer le score de priorité pour chaque axe éligible
  const prioritized: PrioritizedAxis[] = [];
  for (const axis of eligibleAxes) {
    const score = analysis[axis].score;
    const weight = CANONICAL_WEIGHTS[axis];
    const priority = (100 - score) * weight;

    prioritized.push({ axis, score, weight, priority });
  }

  // Trier par priorité décroissante
  prioritized.sort((a, b) => b.priority - a.priority);

  // Limiter à max 2 axes
  return prioritized.slice(0, ENRICHMENT_LIMITS.MAX_AXES);
}

// ═══════════════════════════════════════════════════════════════════
// ENRICHMENT RESULT BUILDER
// ═══════════════════════════════════════════════════════════════════

/**
 * Détermine si l'enrichissement est requis et quels axes cibler.
 */
export function computeEnrichmentDecision(
  analysis: AnalysisAxes,
  globalScore: number,
  confidenceLevel: 'LOW' | 'MEDIUM' | 'HIGH'
): {
  required: boolean;
  trigger_axes: AnalysisAxis[];
  max_questions: number;
} {
  const triggers = detectEnrichmentTriggers(analysis, globalScore, confidenceLevel);

  if (triggers.length === 0) {
    return { required: false, trigger_axes: [], max_questions: 0 };
  }

  const prioritized = prioritizeAxes(analysis, triggers);
  const triggerAxes = prioritized.map((p) => p.axis);

  // Max questions : jusqu'à 3 par axe, max 5 au total
  const maxPerAxes = triggerAxes.length * ENRICHMENT_LIMITS.MAX_QUESTIONS_PER_AXIS;
  const maxQuestions = Math.min(maxPerAxes, ENRICHMENT_LIMITS.MAX_QUESTIONS_PER_SEQUENCE);

  return {
    required: true,
    trigger_axes: triggerAxes,
    max_questions: maxQuestions,
  };
}

// ═══════════════════════════════════════════════════════════════════
// SCORE RECALCULATION AFTER ENRICHMENT (Section 8)
// ═══════════════════════════════════════════════════════════════════

export interface ScoreAdjustment {
  axis: AnalysisAxis;
  question_id: string;
  adjustment: number;
}

/**
 * Applique les ajustements de score après enrichissement.
 * Recalcule le score global et réévalue la décision.
 *
 * Règles :
 * - score_enrichi = score_initial + Σ(ajustements)
 * - Bornage [0, 100]
 * - Recalcul complet du score global
 * - Mise à jour confidence : LOW → MEDIUM si 2+ axes enrichis
 */
export function applyEnrichmentAdjustments(
  currentAnalysis: AnalysisAxes,
  adjustments: ScoreAdjustment[]
): {
  updatedAnalysis: AnalysisAxes;
  newGlobalScore: number;
  enrichedAxes: Set<AnalysisAxis>;
} {
  const updatedAnalysis: AnalysisAxes = JSON.parse(JSON.stringify(currentAnalysis));
  const enrichedAxes = new Set<AnalysisAxis>();

  // Grouper les ajustements par axe et appliquer
  for (const adj of adjustments) {
    const currentScore = updatedAnalysis[adj.axis].score;
    updatedAnalysis[adj.axis].score = Math.max(
      SCORE_RANGE.MIN,
      Math.min(SCORE_RANGE.MAX, currentScore + adj.adjustment)
    );
    enrichedAxes.add(adj.axis);
  }

  const newGlobalScore = calculateGlobalScore(updatedAnalysis);

  return { updatedAnalysis, newGlobalScore, enrichedAxes };
}

/**
 * Met à jour le niveau de confiance après enrichissement.
 * LOW → MEDIUM si 2+ axes ont été enrichis.
 * MEDIUM → HIGH si tous les axes enrichis ont score >= 60.
 */
export function updateConfidenceLevel(
  currentLevel: 'LOW' | 'MEDIUM' | 'HIGH',
  enrichedAxes: Set<AnalysisAxis>,
  updatedAnalysis: AnalysisAxes
): 'LOW' | 'MEDIUM' | 'HIGH' {
  if (currentLevel === 'HIGH') return 'HIGH';

  if (currentLevel === 'LOW' && enrichedAxes.size >= 2) {
    return 'MEDIUM';
  }

  if (currentLevel === 'MEDIUM') {
    const allAbove60 = Array.from(enrichedAxes).every(
      (axis) => updatedAnalysis[axis].score >= 60
    );
    if (allAbove60 && enrichedAxes.size >= 2) {
      return 'HIGH';
    }
  }

  return currentLevel;
}

