import { describe, test, expect } from 'vitest';
import { validateAnalysisInput, validateAnalysisOutput } from '@/lib/analysis/validators';

// ─── Fixtures ────────────────────────────────────────────────────
import validInput from '@/lib/analysis/fixtures/analysis-v1.0/inputs/valid-simple-idea.json';
import invalidInput from '@/lib/analysis/fixtures/analysis-v1.0/inputs/invalid-missing-schema-version.json';
import validOutput from '@/lib/analysis/fixtures/analysis-v1.0/outputs/valid-simple-idea-expected-output.json';
import invalidOutput from '@/lib/analysis/fixtures/analysis-v1.0/outputs/invalid-score-out-of-range.json';

// ═══════════════════════════════════════════════════════════════════
// INPUT VALIDATION
// ═══════════════════════════════════════════════════════════════════

describe('validateAnalysisInput', () => {
  test('should accept valid input (valid-simple-idea.json)', () => {
    const result = validateAnalysisInput(validInput);
    expect(result.valid).toBe(true);
    expect(result.data).toBeDefined();
    expect(result.errors).toBeUndefined();
  });

  test('should reject input missing schema_version', () => {
    const result = validateAnalysisInput(invalidInput);
    expect(result.valid).toBe(false);
    expect(result.errors).toBeDefined();
    expect(result.errors!.length).toBeGreaterThan(0);
    // Should mention schema_version
    const hasSchemaVersionError = result.errors!.some(
      (e) => e.includes('schema_version')
    );
    expect(hasSchemaVersionError).toBe(true);
  });

  test('should reject empty object', () => {
    const result = validateAnalysisInput({});
    expect(result.valid).toBe(false);
  });

  test('should reject text too short (< 10 chars)', () => {
    const input = {
      ...validInput,
      inputs: {
        text: {
          content: 'Short',
          source: 'typed',
          length: 5,
        },
      },
    };
    const result = validateAnalysisInput(input);
    expect(result.valid).toBe(false);
  });

  test('should reject invalid state', () => {
    const input = {
      ...validInput,
      idea: { ...validInput.idea, state: 'INVALID_STATE' },
    };
    const result = validateAnalysisInput(input);
    expect(result.valid).toBe(false);
  });

  test('should reject more than 5 links', () => {
    const links = Array.from({ length: 6 }, (_, i) => ({
      url: `https://example.com/${i}`,
      type: 'web' as const,
    }));
    const input = {
      ...validInput,
      inputs: { ...validInput.inputs, links },
    };
    const result = validateAnalysisInput(input);
    expect(result.valid).toBe(false);
  });

  test('should reject more than 3 files', () => {
    const files = Array.from({ length: 4 }, (_, i) => ({
      file_id: `file_${i}`,
      type: 'pdf' as const,
      size_kb: 100,
    }));
    const input = {
      ...validInput,
      inputs: { ...validInput.inputs, files },
    };
    const result = validateAnalysisInput(input);
    expect(result.valid).toBe(false);
  });

  test('should reject invalid language code format', () => {
    const input = {
      ...validInput,
      meta: { ...validInput.meta, language: 'french' },
    };
    const result = validateAnalysisInput(input);
    expect(result.valid).toBe(false);
  });
});

// ═══════════════════════════════════════════════════════════════════
// OUTPUT VALIDATION
// ═══════════════════════════════════════════════════════════════════

describe('validateAnalysisOutput', () => {
  test('should accept valid output (valid-simple-idea-expected-output.json)', () => {
    const result = validateAnalysisOutput(validOutput);
    expect(result.valid).toBe(true);
    expect(result.data).toBeDefined();
    expect(result.errors).toBeUndefined();
  });

  test('should reject output with score out of range (> 100)', () => {
    const result = validateAnalysisOutput(invalidOutput);
    expect(result.valid).toBe(false);
    expect(result.errors).toBeDefined();
    // Should detect score > 100 for problem
    const hasScoreError = result.errors!.some(
      (e) => e.includes('analysis.problem.score') || e.includes('score')
    );
    expect(hasScoreError).toBe(true);
  });

  test('should reject output with negative score', () => {
    const result = validateAnalysisOutput(invalidOutput);
    expect(result.valid).toBe(false);
    // Should detect score < 0 for feasibility
    const hasNegativeError = result.errors!.some(
      (e) => e.includes('feasibility') || e.includes('score')
    );
    expect(hasNegativeError).toBe(true);
  });

  test('should reject output with invalid decision', () => {
    const result = validateAnalysisOutput(invalidOutput);
    expect(result.valid).toBe(false);
    const hasDecisionError = result.errors!.some(
      (e) => e.includes('recommendation') || e.includes('decision')
    );
    expect(hasDecisionError).toBe(true);
  });

  test('should reject output with wrong weights', () => {
    const output = JSON.parse(JSON.stringify(validOutput));
    output.scores.weights.problem = 0.5; // Wrong weight
    const result = validateAnalysisOutput(output);
    expect(result.valid).toBe(false);
  });

  test('should reject output with justification too short', () => {
    const output = JSON.parse(JSON.stringify(validOutput));
    output.analysis.problem.justification = 'Too short'; // < 20 chars
    const result = validateAnalysisOutput(output);
    expect(result.valid).toBe(false);
  });

  test('should reject output with more than 5 risks', () => {
    const output = JSON.parse(JSON.stringify(validOutput));
    output.risks = Array.from({ length: 6 }, () => ({
      axis: 'market',
      description: 'A risk description that is long enough',
      severity: 'MEDIUM',
    }));
    const result = validateAnalysisOutput(output);
    expect(result.valid).toBe(false);
  });

  test('should reject output with more than 3 levers', () => {
    const output = JSON.parse(JSON.stringify(validOutput));
    output.levers = Array.from({ length: 4 }, () => ({
      axis: 'market',
      action: 'An action description that is long enough',
      expected_impact: 'HIGH',
    }));
    const result = validateAnalysisOutput(output);
    expect(result.valid).toBe(false);
  });
});

