/**
 * K3RN.LABS — Tests du calcul de score global
 * Source de vérité : Contrat Canonique v1.1, Section 4.3
 * Fixture de référence : valid-simple-idea-expected-output.json
 */

import { describe, test, expect } from 'vitest';
import { calculateGlobalScore, verifyGlobalScore, recalculateAfterEnrichment } from '@/lib/analysis/scoring';
import { CANONICAL_WEIGHTS } from '@/lib/analysis/constants';
import type { AnalysisAxes } from '@/lib/analysis/types';
import validOutput from '@/lib/analysis/fixtures/analysis-v1.0/outputs/valid-simple-idea-expected-output.json';

// ─── Fixture analysis data ──────────────────────────────────────
const fixtureAnalysis = validOutput.analysis as AnalysisAxes;

describe('calculateGlobalScore', () => {
  test('should match fixture: (72×0.2)+(58×0.2)+(65×0.15)+(42×0.15)+(55×0.2)+(50×0.1) = 58', () => {
    const score = calculateGlobalScore(fixtureAnalysis);
    expect(score).toBe(58);
  });

  test('should match fixture global_score exactly', () => {
    const score = calculateGlobalScore(fixtureAnalysis);
    expect(score).toBe(validOutput.scores.global_score);
  });

  test('should verify the manual calculation step by step', () => {
    // Vérification manuelle de la formule canonique
    const expected =
      72 * 0.2 +   // problem
      58 * 0.2 +   // market
      65 * 0.15 +  // differentiation
      42 * 0.15 +  // feasibility
      55 * 0.2 +   // business
      50 * 0.1;    // founder_fit

    expect(expected).toBeCloseTo(58.05, 1);
    expect(Math.round(expected)).toBe(58);
  });

  test('should return 0 for all zeros', () => {
    const zeroAnalysis: AnalysisAxes = {
      problem: { score: 0, justification: 'Zero test for validation.', blocking_gap: false },
      market: { score: 0, justification: 'Zero test for validation.', blocking_gap: false },
      differentiation: { score: 0, justification: 'Zero test for validation.', blocking_gap: false },
      feasibility: { score: 0, justification: 'Zero test for validation.', blocking_gap: false },
      business: { score: 0, justification: 'Zero test for validation.', blocking_gap: false },
      founder_fit: { score: 0, justification: 'Zero test for validation.', blocking_gap: false },
    };
    expect(calculateGlobalScore(zeroAnalysis)).toBe(0);
  });

  test('should return 100 for all perfect scores', () => {
    const perfectAnalysis: AnalysisAxes = {
      problem: { score: 100, justification: 'Perfect score for testing.', blocking_gap: false },
      market: { score: 100, justification: 'Perfect score for testing.', blocking_gap: false },
      differentiation: { score: 100, justification: 'Perfect score for testing.', blocking_gap: false },
      feasibility: { score: 100, justification: 'Perfect score for testing.', blocking_gap: false },
      business: { score: 100, justification: 'Perfect score for testing.', blocking_gap: false },
      founder_fit: { score: 100, justification: 'Perfect score for testing.', blocking_gap: false },
    };
    expect(calculateGlobalScore(perfectAnalysis)).toBe(100);
  });

  test('should correctly apply canonical weights (example from docs)', () => {
    // Exemple du contrat : Problème=75, Marché=60, Diff=55, Faisabilité=70, Business=50, Founder=80
    // → 15 + 12 + 8.25 + 10.5 + 10 + 8 = 63.75 → 64
    const docExample: AnalysisAxes = {
      problem: { score: 75, justification: 'Contrat example problem score.', blocking_gap: false },
      market: { score: 60, justification: 'Contrat example market score.', blocking_gap: false },
      differentiation: { score: 55, justification: 'Contrat example diff score.', blocking_gap: false },
      feasibility: { score: 70, justification: 'Contrat example feasibility.', blocking_gap: false },
      business: { score: 50, justification: 'Contrat example business score.', blocking_gap: false },
      founder_fit: { score: 80, justification: 'Contrat example founder fit.', blocking_gap: false },
    };
    expect(calculateGlobalScore(docExample)).toBe(64);
  });

  test('should round 0.5 up (Math.round behavior)', () => {
    // Construisons un cas qui donne exactement .5
    // problem=25 × 0.2 = 5.0
    // market=25 × 0.2 = 5.0
    // diff=0 × 0.15 = 0
    // feas=0 × 0.15 = 0
    // business=0 × 0.2 = 0
    // founder=25 × 0.1 = 2.5
    // Total = 12.5 → 13
    const halfCase: AnalysisAxes = {
      problem: { score: 25, justification: 'Half case test for rounding.', blocking_gap: false },
      market: { score: 25, justification: 'Half case test for rounding.', blocking_gap: false },
      differentiation: { score: 0, justification: 'Half case test for rounding.', blocking_gap: false },
      feasibility: { score: 0, justification: 'Half case test for rounding.', blocking_gap: false },
      business: { score: 0, justification: 'Half case test for rounding.', blocking_gap: false },
      founder_fit: { score: 25, justification: 'Half case test for rounding.', blocking_gap: false },
    };
    expect(calculateGlobalScore(halfCase)).toBe(13);
  });
});

describe('verifyGlobalScore', () => {
  test('should return true for correct score', () => {
    expect(verifyGlobalScore(fixtureAnalysis, 58)).toBe(true);
  });

  test('should return false for incorrect score', () => {
    expect(verifyGlobalScore(fixtureAnalysis, 60)).toBe(false);
  });
});

describe('recalculateAfterEnrichment', () => {
  test('should correctly recalculate after positive adjustments', () => {
    const adjustments = new Map<string, number>();
    adjustments.set('feasibility', 20); // 42 → 62
    adjustments.set('business', 10);    // 55 → 65

    const { globalScore, updatedAnalysis } = recalculateAfterEnrichment(
      fixtureAnalysis,
      adjustments as Map<any, number>
    );

    expect(updatedAnalysis.feasibility.score).toBe(62);
    expect(updatedAnalysis.business.score).toBe(65);
    // Other axes unchanged
    expect(updatedAnalysis.problem.score).toBe(72);
    // Recalculated: (72×0.2)+(58×0.2)+(65×0.15)+(62×0.15)+(65×0.2)+(50×0.1) = 64.05 → 64
    expect(globalScore).toBe(64);
  });

  test('should clamp scores to [0, 100]', () => {
    const adjustments = new Map<string, number>();
    adjustments.set('problem', 50); // 72 + 50 = 122 → 100

    const { updatedAnalysis } = recalculateAfterEnrichment(
      fixtureAnalysis,
      adjustments as Map<any, number>
    );

    expect(updatedAnalysis.problem.score).toBe(100);
  });

  test('should clamp negative scores to 0', () => {
    const adjustments = new Map<string, number>();
    adjustments.set('feasibility', -50); // 42 - 50 = -8 → 0

    const { updatedAnalysis } = recalculateAfterEnrichment(
      fixtureAnalysis,
      adjustments as Map<any, number>
    );

    expect(updatedAnalysis.feasibility.score).toBe(0);
  });

  test('should not modify original analysis', () => {
    const original = JSON.parse(JSON.stringify(fixtureAnalysis));
    const adjustments = new Map<string, number>();
    adjustments.set('feasibility', 20);

    recalculateAfterEnrichment(fixtureAnalysis, adjustments as Map<any, number>);

