    const result = determineDecision(80, analysis, 'LOW');
    expect(result.recommendation).toBe('EXPLORE');
  });
});

// ═══════════════════════════════════════════════════════════════════
// PRIORITY CONFLICTS (Section 5.2)
// ═══════════════════════════════════════════════════════════════════

describe('Priority conflicts', () => {
  test('KILL should override GO when blocking_gap exists', () => {
