/**
 * K3RN.LABS — Tests enrichissement (triggers, priorisation, recalcul)
 * Source de vérité : Contrat Questions Guidées & Enrichissement v1.1
 */

import { describe, test, expect } from 'vitest';
import {
  detectEnrichmentTriggers,
  prioritizeAxes,
  computeEnrichmentDecision,
  applyEnrichmentAdjustments,
  updateConfidenceLevel,
} from '@/lib/analysis/enrichment';
import type { AnalysisAxes } from '@/lib/analysis/types';
import type { AnalysisAxis } from '@/lib/analysis/constants';
import validOutput from '@/lib/analysis/fixtures/analysis-v1.0/outputs/valid-simple-idea-expected-output.json';

const fixtureAnalysis = validOutput.analysis as AnalysisAxes;

// ═══════════════════════════════════════════════════════════════════
// TRIGGER DETECTION
// ═══════════════════════════════════════════════════════════════════

describe('detectEnrichmentTriggers', () => {
  test('should detect feasibility < 40 in fixture', () => {
    // feasibility = 42, which is >= 40, so no trigger on that alone
    // But the fixture says enrichment is required on feasibility and business
    // Let's test with score explicitly < 40
    const analysis: AnalysisAxes = {
      ...fixtureAnalysis,
      feasibility: { ...fixtureAnalysis.feasibility, score: 35 },
    };
    const triggers = detectEnrichmentTriggers(analysis, 55, 'MEDIUM');
    const feasibilityTrigger = triggers.find((t) => t.axis === 'feasibility');
    expect(feasibilityTrigger).toBeDefined();
    expect(feasibilityTrigger!.type).toBe('axis_below_threshold');
  });

  test('should NOT trigger when score >= 40', () => {
    const analysis: AnalysisAxes = {
      ...fixtureAnalysis,
      feasibility: { ...fixtureAnalysis.feasibility, score: 42 },
    };
    const triggers = detectEnrichmentTriggers(analysis, 58, 'MEDIUM');
    const axisTriggers = triggers.filter((t) => t.type === 'axis_below_threshold');
    // No axis should be < 40 in the fixture (feasibility=42 is >= 40)
    expect(axisTriggers.every((t) => t.axis !== 'feasibility')).toBe(true);
  });

  test('should NOT trigger when blocking_gap = true', () => {
    const analysis: AnalysisAxes = {
      ...fixtureAnalysis,
      feasibility: { score: 30, justification: 'Test blocking gap handling.', blocking_gap: true },
    };
    const triggers = detectEnrichmentTriggers(analysis, 55, 'MEDIUM');
    const feasibilityTrigger = triggers.find(
      (t) => t.axis === 'feasibility' && t.type === 'axis_below_threshold'
    );
    expect(feasibilityTrigger).toBeUndefined();
  });

  test('should trigger on low confidence with medium score', () => {
    const triggers = detectEnrichmentTriggers(fixtureAnalysis, 58, 'LOW');
    const confidenceTrigger = triggers.find(
      (t) => t.type === 'low_confidence_medium_score'
    );
    expect(confidenceTrigger).toBeDefined();
  });

