// CONFIDENCE UPDATE
// ═══════════════════════════════════════════════════════════════════

describe('updateConfidenceLevel', () => {
  test('LOW → MEDIUM when 2+ axes enriched', () => {
    const enriched = new Set<AnalysisAxis>(['feasibility', 'business']);
