    const decisionResult = determineDecision(
      globalScore,
      analysis,
      llmData.decision.confidence_level
    );

    // ─── 10. Detect enrichment triggers ─────────────────────────
    const enrichment = computeEnrichmentDecision(
      analysis,
      globalScore,
      llmData.decision.confidence_level
    );

    // ─── 11. Determine inputs_used ──────────────────────────────
    const inputsUsed: ('text' | 'voice' | 'link' | 'file')[] = [];
    if (input.inputs.text) {
      inputsUsed.push(input.inputs.text.source === 'voice_transcript' ? 'voice' : 'text');
    }
    if (input.inputs.links && input.inputs.links.length > 0) {
      inputsUsed.push('link');
    }
    if (input.inputs.files && input.inputs.files.length > 0) {
      inputsUsed.push('file');
    }

    // ─── 12. Assemble canonical output ──────────────────────────
    const analysisId = crypto.randomUUID();

    const output: AnalysisOutput = {
      meta: {
        schema_version: SCHEMA_VERSION,
        analysis_id: analysisId,
        timestamp: new Date().toISOString(),
        orchestrator_version: `v${CURRENT_VERSION.replace('v', '')}`,
        model: AI_MODEL,
      },
      idea: {
        idea_id: input.idea.idea_id,
        title: llmData.idea.title,
        raw_summary: llmData.idea.raw_summary,
        inputs_used: inputsUsed.length > 0 ? inputsUsed : ['text'],
      },
      analysis,
      scores: {
        global_score: globalScore,
        weights: CANONICAL_WEIGHTS,
      },
      decision: {
        recommendation: decisionResult.recommendation,
        confidence_level: llmData.decision.confidence_level,
        summary: llmData.decision.summary,
      },
      risks: llmData.risks,
      levers: llmData.levers,
      enrichment,
      lab_orientation: llmData.lab_orientation,
    };

    // ─── 13. Log for traceability ───────────────────────────────
    const duration = Date.now() - startTime;
    console.log(JSON.stringify({
      event: 'analysis_complete',
      request_id: input.meta.request_id,
      analysis_id: analysisId,
      prompt_version: CURRENT_VERSION,
      model: AI_MODEL,
      schema_version: SCHEMA_VERSION,
      global_score: globalScore,
      recommendation: decisionResult.recommendation,
      enrichment_required: enrichment.required,
      duration_ms: duration,
      success: true,
    }));

    return NextResponse.json(output, { status: 200 });

  } catch (error: unknown) {
    const err = error as Error;
    console.error('Unexpected analysis error:', err);
    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
  }
}

// ═══════════════════════════════════════════════════════════════════
// ERROR HELPER
// ═══════════════════════════════════════════════════════════════════

function errorResponse(status: number, code: string, message: string): NextResponse<ApiError> {
  return NextResponse.json(
    {
      error: {
        code,
        message,
        details: { schema_version: SCHEMA_VERSION },
      },
    },
    { status }
  );
}

