/**
 * K3RN.LABS — Enrichment Questions Generation Prompt v1.0
 * Génère les questions guidées au format Widget Schema
 */

import type { AnalysisAxis } from '../../constants';

export function buildEnrichmentPrompt(
  axes: Array<{ axis: AnalysisAxis; score: number; justification: string }>,
  ideaSummary: string,
  maxQuestions: number
): string {
  const axesDescription = axes
    .map((a) => `- **${a.axis}** : score ${a.score}/100 — ${a.justification}`)
    .join('\n');

  return `## MISSION : GÉNÉRER DES QUESTIONS GUIDÉES D'ENRICHISSEMENT

### CONTEXTE

L'idée suivante a été analysée et nécessite un enrichissement ciblé :

**Résumé de l'idée :** ${ideaSummary}

**Axes à enrichir :**
${axesDescription}

### OBJECTIF

Génère exactement ${maxQuestions} questions guidées qui vont permettre de réduire l'incertitude sur les axes listés ci-dessus.

### RÈGLES STRICTES

1. Chaque question est rattachée à UN SEUL axe
2. Priorité aux questions fermées (single_select) et choix multiples (multi_select)
3. Maximum 3 questions par axe
4. Chaque question doit avoir un impact mesurable sur le score
5. Ne PAS poser de questions dont la réponse est déjà dans la description de l'idée
6. Les questions doivent être répondables en 8-18 secondes chacune
7. score_adjustment dans [-25, +25]

### FORMAT DE SORTIE (JSON ARRAY)

Retourne EXCLUSIVEMENT un tableau JSON, sans texte autour :

[
  {
    "question_id": "q_[axis]_001",
    "axis": "market" | "problem" | "differentiation" | "feasibility" | "business" | "founder_fit",
    "type": "single_select" | "multi_select" | "range" | "ranking",
    "prompt": "Question claire et concise (10-200 chars)",
    "options": [
      {
        "id": "opt_001",
        "label": "Label clair",
        "value": "identifiant_court",
        "score_adjustment": number (-25 à +25)
      }
    ],
    "allow_skip": false,
    "timeout_seconds": 60,
    "expected_impact": {
      "axis": "même axe que la question",
      "min_adjustment": number (plus petit score_adjustment des options),
      "max_adjustment": number (plus grand score_adjustment des options)
    }
  }
]

Contraintes options :
- 2 à 5 options par question
- IDs uniques
- score_adjustment reflète l'impact réel de la réponse sur l'évaluation de l'axe`;
}

