/**
 * K3RN.LABS — POST /api/enrichment
 *
 * Deux modes d'opération :
 *
 * MODE 1 — Générer les questions (body.action = "generate")
 *   Input: analysis + scores + decision
 *   Output: questions guidées au format Widget Schema
 *
 * MODE 2 — Soumettre les réponses et recalculer (body.action = "submit")
 *   Input: enrichment_id + responses
 *   Output: scores recalculés + nouvelle décision
 */

import { NextResponse } from 'next/server';
import Anthropic from '@anthropic-ai/sdk';
import { z } from 'zod';
import {
  detectEnrichmentTriggers,
  prioritizeAxes,
  computeEnrichmentDecision,
  applyEnrichmentAdjustments,
  updateConfidenceLevel,
  type ScoreAdjustment,
} from '@/lib/analysis/enrichment';
import { calculateGlobalScore } from '@/lib/analysis/scoring';
import { determineDecision } from '@/lib/analysis/decision';
import { enrichmentQuestionSchema, enrichmentResponseSchema } from '@/lib/analysis/validators';
import { CANONICAL_WEIGHTS, SCHEMA_VERSION, type AnalysisAxis } from '@/lib/analysis/constants';
import { assembleSystemPrompt } from '@/lib/analysis/prompts/registry';
import { buildEnrichmentPrompt } from '@/lib/analysis/prompts/v1.0/enrichment';
import type { AnalysisAxes, EnrichmentQuestion, ApiError } from '@/lib/analysis/types';

const anthropic = new Anthropic({
  apiKey: process.env.ANTHROPIC_API_KEY,
});

const AI_MODEL = process.env.AI_MODEL || 'claude-opus-4-20250918';

// ─── Request schemas ────────────────────────────────────────────

const axisAnalysisSchema = z.object({
  score: z.number().int().min(0).max(100),
  justification: z.string().min(20).max(300),
  blocking_gap: z.boolean(),
});

const generateRequestSchema = z.object({
  action: z.literal('generate'),
  idea_id: z.string().min(1),
  idea_summary: z.string().min(10),
  analysis: z.object({
    problem: axisAnalysisSchema,
    market: axisAnalysisSchema,
    differentiation: axisAnalysisSchema,
    feasibility: axisAnalysisSchema,
    business: axisAnalysisSchema,
    founder_fit: axisAnalysisSchema,
  }),
  scores: z.object({
    global_score: z.number().int().min(0).max(100),
  }),
  decision: z.object({
    recommendation: z.enum(['GO', 'EXPLORE', 'PARK', 'KILL']),
    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
  }),
});

const submitRequestSchema = z.object({
  action: z.literal('submit'),
  enrichment_id: z.string().min(1),
  idea_id: z.string().min(1),
  analysis: z.object({
    problem: axisAnalysisSchema,
    market: axisAnalysisSchema,
    differentiation: axisAnalysisSchema,
    feasibility: axisAnalysisSchema,
    business: axisAnalysisSchema,
    founder_fit: axisAnalysisSchema,
  }),
  scores: z.object({
    global_score: z.number().int().min(0).max(100),
  }),
  decision: z.object({
    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
  }),
  questions: z.array(z.object({
    question_id: z.string(),
    axis: z.enum(['problem', 'market', 'differentiation', 'feasibility', 'business', 'founder_fit']),
    options: z.array(z.object({
      id: z.string(),
      score_adjustment: z.number(),
    })),
  })),
  responses: z.array(enrichmentResponseSchema),
});

// ═══════════════════════════════════════════════════════════════════
// POST /api/enrichment
// ═══════════════════════════════════════════════════════════════════

export async function POST(req: Request) {
  try {
    let body: unknown;
    try {
      body = await req.json();
    } catch {
      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Request body is not valid JSON');
    }

    // Determine action
    const actionCheck = z.object({ action: z.enum(['generate', 'submit']) }).safeParse(body);
    if (!actionCheck.success) {
      return errorResponse(400, 'INPUT_SCHEMA_INVALID', 'Missing or invalid "action" field. Must be "generate" or "submit".');
    }

    if (actionCheck.data.action === 'generate') {
      return handleGenerate(body);
    } else {
      return handleSubmit(body);
    }
  } catch (error: unknown) {
    const err = error as Error;
    console.error('Unexpected enrichment error:', err);
    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
  }
}

// ═══════════════════════════════════════════════════════════════════
// MODE 1 : GENERATE QUESTIONS
// ═══════════════════════════════════════════════════════════════════

async function handleGenerate(body: unknown) {
  const validation = generateRequestSchema.safeParse(body);
  if (!validation.success) {
    return errorResponse(400, 'INPUT_SCHEMA_INVALID', validation.error.issues.map((i) => `${i.path.join('.')} ${i.message}`).join('; '));
  }

  const data = validation.data;
  const analysis = data.analysis as AnalysisAxes;

  // ─── Check enrichment is actually needed ──────────────────────
  const enrichment = computeEnrichmentDecision(
    analysis,
    data.scores.global_score,
    data.decision.confidence_level
  );

  if (!enrichment.required) {
    return NextResponse.json({
      enrichment_id: null,
      required: false,
      message: 'No enrichment triggers detected',
      trigger_axes: [],
      questions: [],
    });
  }

  // ─── Build enrichment prompt ──────────────────────────────────
  const triggers = detectEnrichmentTriggers(
    analysis,
    data.scores.global_score,
    data.decision.confidence_level
  );
  const prioritized = prioritizeAxes(analysis, triggers);

  const axesInfo = prioritized.map((p) => ({
    axis: p.axis,
    score: p.score,
    justification: analysis[p.axis].justification,
  }));

  const enrichmentPrompt = buildEnrichmentPrompt(
    axesInfo,
    data.idea_summary,
    enrichment.max_questions
  );

  // ─── Call Claude API to generate questions ────────────────────
  let questionsJson: string;
  try {
    const message = await anthropic.messages.create({
      model: AI_MODEL,
      max_tokens: 2048,
      temperature: 0.3,
      system: assembleSystemPrompt(),
      messages: [{ role: 'user', content: enrichmentPrompt }],
    });

    const textBlock = message.content.find((b) => b.type === 'text');
    if (!textBlock || textBlock.type !== 'text') {
      return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'LLM returned no text content');
    }
    questionsJson = textBlock.text;
  } catch (error: unknown) {
    const err = error as Error;
    console.error('Claude API error (enrichment):', err);
    return errorResponse(500, 'AI_CALL_FAILED', `Claude API error: ${err.message}`);
  }

  // ─── Parse and validate questions ─────────────────────────────
  let parsedQuestions: unknown;
  try {
    let jsonStr = questionsJson.trim();
    if (jsonStr.startsWith('```json')) jsonStr = jsonStr.slice(7);
    else if (jsonStr.startsWith('```')) jsonStr = jsonStr.slice(3);
    if (jsonStr.endsWith('```')) jsonStr = jsonStr.slice(0, -3);
    parsedQuestions = JSON.parse(jsonStr.trim());
  } catch {
    console.error('Enrichment JSON parse error:', questionsJson.substring(0, 500));
    return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'LLM output is not valid JSON');
  }

  // Validate each question
  if (!Array.isArray(parsedQuestions)) {
    return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'LLM output is not a JSON array');
  }

  const validatedQuestions: EnrichmentQuestion[] = [];
  for (const q of parsedQuestions) {
    const qValidation = enrichmentQuestionSchema.safeParse(q);
    if (qValidation.success) {
      validatedQuestions.push(qValidation.data as EnrichmentQuestion);
    } else {
      console.warn('Invalid question skipped:', qValidation.error.issues);
    }
  }

  if (validatedQuestions.length === 0) {
    return errorResponse(500, 'ENRICHMENT_GENERATION_FAILED', 'No valid questions generated by LLM');
  }

  const enrichmentId = crypto.randomUUID();

  return NextResponse.json({
    enrichment_id: enrichmentId,
    idea_id: data.idea_id,
    required: true,
    timestamp: new Date().toISOString(),
    trigger_axes: enrichment.trigger_axes,
    questions: validatedQuestions,
    max_questions: enrichment.max_questions,
  });
}

// ═══════════════════════════════════════════════════════════════════
// MODE 2 : SUBMIT RESPONSES & RECALCULATE
// ═══════════════════════════════════════════════════════════════════

async function handleSubmit(body: unknown) {
  const validation = submitRequestSchema.safeParse(body);
  if (!validation.success) {
    return errorResponse(400, 'INPUT_SCHEMA_INVALID', validation.error.issues.map((i) => `${i.path.join('.')} ${i.message}`).join('; '));
  }

  const data = validation.data;
  const analysis = data.analysis as AnalysisAxes;

  // ─── Calculate adjustments from responses ─────────────────────
  const adjustments: ScoreAdjustment[] = [];

  for (const response of data.responses) {
    if (response.status !== 'completed' || !response.selected_option_ids) {
      continue; // skipped or timeout → no adjustment
    }

    // Find the corresponding question
    const question = data.questions.find((q) => q.question_id === response.question_id);
    if (!question) continue;

    // Sum adjustments for selected options
    let totalAdjustment = 0;
    for (const optionId of response.selected_option_ids) {
      const option = question.options.find((o) => o.id === optionId);
      if (option) {
        totalAdjustment += option.score_adjustment;
      }
    }

    adjustments.push({
      axis: question.axis as AnalysisAxis,
      question_id: response.question_id,
      adjustment: totalAdjustment,
    });
  }

  // ─── Apply adjustments ────────────────────────────────────────
  const { updatedAnalysis, newGlobalScore, enrichedAxes } =
    applyEnrichmentAdjustments(analysis, adjustments);

  // ─── Update confidence level ──────────────────────────────────
  const newConfidence = updateConfidenceLevel(
    data.decision.confidence_level,
    enrichedAxes,
    updatedAnalysis
  );

  // ─── Re-determine decision ────────────────────────────────────
  const newDecision = determineDecision(newGlobalScore, updatedAnalysis, newConfidence);

  // ─── Build scores maps ────────────────────────────────────────
  const scoresBefore: Record<string, number> = {};
  const scoresAfter: Record<string, number> = {};
  for (const [axis, value] of Object.entries(analysis)) {
    scoresBefore[axis] = value.score;
  }
  scoresBefore['global'] = data.scores.global_score;
  for (const [axis, value] of Object.entries(updatedAnalysis)) {
    scoresAfter[axis] = value.score;
  }
  scoresAfter['global'] = newGlobalScore;

  return NextResponse.json({
    enrichment_id: data.enrichment_id,
    idea_id: data.idea_id,
    timestamp: new Date().toISOString(),
    scores_before: scoresBefore,
    scores_after: scoresAfter,
    decision_before: data.decision,
    decision_after: {
      recommendation: newDecision.recommendation,
      confidence_level: newConfidence,
      reasons: newDecision.reasons,
    },
    adjustments,
    updated_analysis: updatedAnalysis,
    updated_scores: {
      global_score: newGlobalScore,
      weights: CANONICAL_WEIGHTS,
    },
  });
}

// ═══════════════════════════════════════════════════════════════════
// ERROR HELPER
// ═══════════════════════════════════════════════════════════════════

function errorResponse(status: number, code: string, message: string): NextResponse<ApiError> {
  return NextResponse.json(
    {
      error: {
        code,
        message,
        details: { schema_version: SCHEMA_VERSION },
      },
    },
    { status }
  );
}

