      success: true,
    }));

    return NextResponse.json(output, { status: 200 });

  } catch (error: unknown) {
    const err = error as Error;
    console.error('Unexpected analysis error:', err);
    return errorResponse(500, 'INTERNAL_ERROR', `Unexpected error: ${err.message}`);
  }
