     3→import React, { createContext, useContext, useState, useEffect } from "react";
     4→import { dictionary, Locale } from "@/lib/i18n/dictionary";
     5→
     6→interface LanguageContextType {
     7→    currentLang: Locale;
     8→    t: typeof dictionary["FR"];
     9→    setLang: (lang: Locale) => void;
    10→}
    11→
    12→const LanguageContext = createContext<LanguageContextType | undefined>(undefined);
    13→
    14→export function LanguageProvider({ children }: { children: React.ReactNode }) {
    15→    const [currentLang, setCurrentLang] = useState<Locale>("FR");
    16→
    17→    const setLang = (lang: Locale) => {
    18→        setCurrentLang(lang);
    19→        if (typeof document !== "undefined") {
    20→            document.documentElement.lang = lang.toLowerCase();
    21→        }
    22→    };
    23→
    24→    const value = {
    25→        currentLang,
    26→        t: dictionary[currentLang],
    27→        setLang,
    28→    };
    29→
    30→    return (
    31→        <LanguageContext.Provider value={value}>
    32→            {children}
    33→        </LanguageContext.Provider>
    34→    );
    35→}
    36→
    37→export function useLanguage() {
    38→    const context = useContext(LanguageContext);
    39→    if (context === undefined) {
    40→        throw new Error("useLanguage must be used within a LanguageProvider");
    41→    }
    42→    return context;
    43→}
