   162→// ═══════════════════════════════════════════════════════════════════
   163→
   164→export const llmRawOutputSchema = z.object({
   165→  idea: z.object({
   166→    title: z.string().min(3).max(200),
   167→    raw_summary: z.string().min(10).max(500),
   168→  }),
   169→  analysis: analysisAxesSchema,
   170→  decision: z.object({
   171→    confidence_level: z.enum(['LOW', 'MEDIUM', 'HIGH']),
   172→    summary: z.string().min(20).max(500),
   173→  }),
   174→  risks: z.array(riskSchema).max(5),
   175→  levers: z.array(leverSchema).max(3),
   176→  lab_orientation: z.object({
