   215→
   216→// ═══════════════════════════════════════════════════════════════════
   217→// VALIDATION HELPERS
   218→// ═══════════════════════════════════════════════════════════════════
   219→
   220→export interface ValidationResult<T> {
   221→  valid: boolean;
   222→  data?: T;
   223→  errors?: string[];
   224→}
   225→
   226→export function validateAnalysisInput(data: unknown): ValidationResult<z.infer<typeof analysisInputSchema>> {
   227→  const result = analysisInputSchema.safeParse(data);
   228→  if (result.success) {
   229→    return { valid: true, data: result.data };
