### STEP 1: Create a Canonical Input Builder Utility

**New file:** `/Users/user/Desktop/K3rn.labas_test/k3rn-platform/src/lib/analysis/build-canonical-input.ts`

This utility transforms the frontend capture data into the canonical `AnalysisInput` format expected by `POST /api/analysis`.

```typescript
import { v4 as uuidv4 } from 'uuid';
import type { AnalysisInput, AnalysisInputLink, AnalysisInputFile } from './types';
import { SCHEMA_VERSION } from './constants';

interface CaptureData {
  text: string;
  files: File[];
  links: string[];
  isVoice?: boolean;
}

export function buildCanonicalInput(data: CaptureData, lang: string): AnalysisInput {
  const input: AnalysisInput = {
    meta: {
      schema_version: SCHEMA_VERSION,
      request_id: uuidv4(),
      timestamp: new Date().toISOString(),
      language: lang.toLowerCase().substring(0, 2), // "FR" -> "fr"
    },
    idea: {
      idea_id: uuidv4(),
      state: 'CAPTURED',
    },
    inputs: {},
    context: {
      user_id: getOrCreateUserId(),
      experience_level: 'BEGINNER', // default, could be from user profile later
    },
  };

  // Text input
  if (data.text.trim()) {
    input.inputs.text = {
      content: data.text.trim(),
      source: data.isVoice ? 'voice_transcript' : 'typed',
      length: data.text.trim().length,
    };
  }

  // Links
  if (data.links.length > 0) {
    input.inputs.links = data.links.map((url): AnalysisInputLink => ({
      url,
      type: classifyLinkType(url),
    }));
  }

  // Files
  if (data.files.length > 0) {
    input.inputs.files = data.files.map((f): AnalysisInputFile => ({
      file_id: uuidv4(),
      type: classifyFileType(f.type),
      size_kb: Math.round(f.size / 1024),
    }));
  }

  return input;
}

function getOrCreateUserId(): string {
  if (typeof window === 'undefined') return 'anonymous';
  let userId = localStorage.getItem('k3rn_user_id');
  if (!userId) {
    userId = uuidv4();
    localStorage.setItem('k3rn_user_id', userId);
  }
  return userId;
}

function classifyLinkType(url: string): 'web' | 'social' | 'doc' {
  const socialDomains = ['twitter.com', 'x.com', 'linkedin.com', 'facebook.com', 'instagram.com'];
  const docDomains = ['docs.google.com', 'notion.so', 'drive.google.com', 'dropbox.com'];
  try {
    const hostname = new URL(url).hostname;
    if (socialDomains.some(d => hostname.includes(d))) return 'social';
    if (docDomains.some(d => hostname.includes(d))) return 'doc';
  } catch {}
  return 'web';
}

function classifyFileType(mimeType: string): 'pdf' | 'image' | 'text' {
  if (mimeType === 'application/pdf') return 'pdf';
  if (mimeType.startsWith('image/')) return 'image';
  return 'text';
}
```

**Key decisions:**
- `uuid` is already in devDependencies; move it to `dependencies` or use `crypto.randomUUID()` directly (available in all modern browsers and Node 19+). Since the codebase already uses `crypto.randomUUID()` in the API routes, prefer that over the `uuid` package for browser code too. Alternatively, keep `uuid` for the client-side builder since `crypto.randomUUID()` requires a secure context.
- `user_id` is persisted in localStorage for now (no auth integration yet).
- `isVoice` flag tracks whether speech recognition was the primary input source.

