"use client";

import { useEffect, useState } from "react";
import { UserNav } from "@/components/layout/user-nav";
import { useLanguageStore } from "@/store/language-store";
import { Folder, FileBox, Plus, Search, LayoutGrid, List as ListIcon, Clock, ChevronRight, MoreVertical } from "lucide-react";
import { cn } from "@/lib/utils";
import { Button } from "@/components/ui/button";
import { Input } from "@/components/ui/input";
import Link from "next/link";
import { K3rnLogo } from "@/components/ui/k3rn-logo";
import { LanguageSelector } from "@/components/ui/language-selector";

interface Project {
    id: string;
    text: string;
    viabilityScore?: number;
    classification?: string;
    timestamp: string;
    isDemo?: boolean;
    analysis?: any;
}

export default function WorkspacePage() {
    const { t } = useLanguageStore();
    const [projects, setProjects] = useState<Project[]>([]);
    const [viewMode, setViewMode] = useState<"grid" | "list">("grid");
    const [searchQuery, setSearchQuery] = useState("");

    // Load projects from LocalStorage
    useEffect(() => {
        const currentIdea = localStorage.getItem("k3rn_active_project");
        const storedProjects = JSON.parse(localStorage.getItem("k3rn_projects") || "[]");

        if (currentIdea) {
            const idea = JSON.parse(currentIdea);
            const exists = storedProjects.some((p: any) => p.timestamp === idea.timestamp);
            if (!exists) {
                const newProject = {
                    ...idea,
                    id: crypto.randomUUID(),
                    viabilityScore: idea.analysis?.viabilityScore,
                    classification: idea.analysis?.classification
                };
                storedProjects.unshift(newProject);
                localStorage.setItem("k3rn_projects", JSON.stringify(storedProjects));
                localStorage.removeItem("k3rn_active_project");
            }
        }

        if (storedProjects.length === 0) {
            const mocks = [
                { id: "1", text: "Plateforme SaaS de gestion de flottes de drones autonomes", viabilityScore: 88, classification: "ACCELERATE", timestamp: new Date().toISOString(), isDemo: true },
                { id: "2", text: "Marketplace NFT pour brevets industriels", viabilityScore: 42, classification: "REJECT", timestamp: new Date(Date.now() - 86400000).toISOString(), isDemo: true },
                { id: "3", text: "IA générative pour scripts de films", viabilityScore: 76, classification: "INCUBATE", timestamp: new Date(Date.now() - 172800000).toISOString(), isDemo: true },
                { id: "4", text: "Réseau social pour chats (MeowNet)", viabilityScore: 12, classification: "KILL", timestamp: new Date(Date.now() - 432000000).toISOString(), isDemo: true },
            ];
            setProjects(mocks);
        } else {
            setProjects(storedProjects);
        }
    }, []);

    const filteredProjects = projects.filter(p =>
        p.text.toLowerCase().includes(searchQuery.toLowerCase()) ||
        p.classification?.toLowerCase().includes(searchQuery.toLowerCase())
    );

    return (
        <div className="min-h-screen bg-[oklch(0_0_0)] text-[oklch(0.85_0.01_264)] font-sans selection:bg-[#F75105]/30">
            {/* Header */}
            <header className="fixed top-0 left-0 w-full z-50 border-b border-[oklch(0.20_0.01_264)] bg-[oklch(0_0_0)]/80 backdrop-blur-md">
                <div className="max-w-[1400px] mx-auto px-6 h-20 flex items-center justify-between">
                    {/* Brand / Logo (Left) */}
                    <Link href="/" className="flex items-center gap-4 transition-opacity hover:opacity-80">
                        <K3rnLogo size="md" />
                    </Link>

                    {/* Controls (Right) */}
                    <div className="flex items-center gap-4">
                        <LanguageSelector />
                        <div className="h-6 w-[1px] bg-[oklch(0.20_0.01_264)]" /> {/* Divider */}
                        <UserNav />
                    </div>
                </div>
            </header>

            {/* Main Content */}
            <main className="pt-32 pb-20 px-6 max-w-[1400px] mx-auto">

                {/* Page Title & Actions */}
                <div className="flex flex-col md:flex-row justify-between items-end md:items-center gap-8 mb-16">
                    <div>
                        <h1 className="text-[3rem] font-light tracking-[0.05em] leading-none text-white mb-4">
                            Dossiers
                        </h1>
                        <p className="text-[oklch(0.65_0.01_264)] font-light text-lg">
                            {projects.length} projets actifs dans votre espace
                        </p>
                    </div>

                    <div className="flex items-center gap-4 w-full md:w-auto">
                        <div className="relative flex-1 md:w-80">
                            <Search className="absolute left-4 top-1/2 -translate-y-1/2 w-5 h-5 text-[oklch(0.45_0.01_264)]" />
                            <Input
                                value={searchQuery}
                                onChange={(e) => setSearchQuery(e.target.value)}
                                placeholder="Rechercher..."
                                className="h-12 pl-12 bg-[oklch(0.15_0.01_264)] border-transparent focus:border-[#F75105]/50 focus:ring-[#F75105]/20 rounded-lg text-base text-white placeholder:text-[oklch(0.45_0.01_264)] transition-all shadow-sm"
                            />
                        </div>

                        <div className="flex items-center p-1.5 bg-[oklch(0.15_0.01_264)] rounded-lg border border-white/5 h-12">
                            <Button
                                variant="ghost"
                                size="icon"
                                className={cn("h-9 w-9 rounded-md transition-all", viewMode === "grid" ? "bg-[oklch(0.38_0.01_264)] text-white shadow-sm" : "text-[oklch(0.45_0.01_264)] hover:text-white")}
                                onClick={() => setViewMode("grid")}
                            >
                                <LayoutGrid className="w-5 h-5" />
                            </Button>
                            <Button
                                variant="ghost"
                                size="icon"
                                className={cn("h-9 w-9 rounded-md transition-all", viewMode === "list" ? "bg-[oklch(0.38_0.01_264)] text-white shadow-sm" : "text-[oklch(0.45_0.01_264)] hover:text-white")}
                                onClick={() => setViewMode("list")}
                            >
                                <ListIcon className="w-5 h-5" />
                            </Button>
                        </div>
                    </div>
                </div>

                {/* Grid View */}
                {viewMode === "grid" ? (
                    <div className="grid grid-cols-1 md:grid-cols-2 xl:grid-cols-3 gap-8 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        {/* New Project Card */}
                        <Link href="/capture" className="group relative flex flex-col items-center justify-center gap-6 aspect-[4/3] rounded-[24px] border-2 border-dashed border-[oklch(0.20_0.01_264)] hover:border-[#F75105]/50 hover:bg-[oklch(0.15_0.01_264)]/30 transition-all cursor-pointer">
                            <div className="h-16 w-16 rounded-full bg-[oklch(0.15_0.01_264)] flex items-center justify-center group-hover:scale-110 transition-transform group-hover:bg-[#F75105] shadow-lg">
                                <Plus className="w-8 h-8 text-[oklch(0.65_0.01_264)] group-hover:text-white transition-colors" />
                            </div>
                            <span className="font-medium text-lg text-[oklch(0.65_0.01_264)] group-hover:text-white transition-colors">Nouveau Dossier</span>
                        </Link>

                        {/* Project Cards */}
                        {filteredProjects.map((project) => (
                            <div key={project.id} className="group relative bg-[oklch(0.15_0.01_264)] rounded-[24px] border border-[oklch(0.20_0.01_264)] hover:border-[#F75105]/30 shadow-card hover:shadow-[0_0_30px_rgba(247,81,5,0.15)] hover:-translate-y-1 transition-all duration-300 overflow-hidden flex flex-col aspect-[4/3] cursor-pointer">

                                {project.isDemo && (
                                    <div className="absolute top-6 right-6 px-3 py-1 rounded-full text-[10px] font-bold bg-[#F75105]/10 text-[#F75105] border border-[#F75105]/20 uppercase tracking-widest z-10">
                                        Simulated
                                    </div>
                                )}

                                <div className="p-8 flex-1 flex flex-col">
                                    <div className="flex justify-between items-start mb-8">
                                        <div className="p-4 bg-[oklch(0_0_0)] text-[oklch(0.65_0.01_264)] rounded-xl group-hover:text-[#F75105] transition-colors border border-white/5">
                                            <Folder className="w-8 h-8" />
                                        </div>
                                        {project.viabilityScore !== undefined && (
                                            <div className="flex flex-col items-end pt-2">
                                                <span className={cn(
                                                    "text-4xl font-light tracking-tighter",
                                                    project.viabilityScore >= 70 ? "text-white" : "text-[oklch(0.45_0.01_264)]"
                                                )}>
                                                    {project.viabilityScore}<span className="text-lg text-[oklch(0.45_0.01_264)]">%</span>
                                                </span>
                                            </div>
                                        )}
                                    </div>

                                    <h3 className="text-xl font-medium text-white line-clamp-3 leading-relaxed mb-auto group-hover:text-[#F75105] transition-colors">
                                        {project.text}
                                    </h3>

                                    <div className="mt-8 flex items-center justify-between pt-6 border-t border-[oklch(0.20_0.01_264)]">
                                        <span className="flex items-center gap-2 text-sm text-[oklch(0.45_0.01_264)]">
                                            <Clock className="w-4 h-4" />
                                            {new Date(project.timestamp).toLocaleDateString()}
                                        </span>
                                        <span className="font-mono text-[11px] uppercase tracking-wider bg-[oklch(0_0_0)] px-3 py-1.5 rounded-lg text-[oklch(0.65_0.01_264)] border border-white/5">
                                            {project.classification || "DRAFT"}
                                        </span>
                                    </div>
                                </div>
                            </div>
                        ))}
                    </div>
                ) : (
                    /* List View */
                    <div className="bg-[oklch(0.15_0.01_264)] rounded-[24px] border border-[oklch(0.20_0.01_264)] overflow-hidden animate-in fade-in shadow-card">
                        {filteredProjects.map((project, i) => (
                            <Link href={`/workspace/${project.id}`} key={project.id} className="flex items-center gap-6 p-6 border-b last:border-0 border-[oklch(0.20_0.01_264)] hover:bg-[#2F323A] transition-colors cursor-pointer group">
                                <div className="p-4 bg-[oklch(0_0_0)] rounded-xl text-[oklch(0.65_0.01_264)] group-hover:text-[#F75105] transition-colors border border-white/5">
                                    <FileBox className="w-6 h-6" />
                                </div>
                                <div className="flex-1 min-w-0">
                                    <h4 className="text-lg font-medium text-white truncate group-hover:text-[#F75105] transition-colors mb-2">
                                        {project.text}
                                    </h4>
                                    <p className="text-sm text-[oklch(0.45_0.01_264)] flex items-center gap-3">
                                        {project.isDemo && <span className="text-[#F75105] font-bold text-[10px] uppercase tracking-wider">[Simulated]</span>}
                                        <span className="font-mono text-[oklch(0.45_0.01_264)]">ID: {project.id.substring(0, 8)}</span>
                                        <span className="opacity-30">•</span>
                                        <span>{new Date(project.timestamp).toLocaleDateString()}</span>
                                    </p>
                                </div>
                                <div className="flex items-center gap-8 pr-4">
                                    {project.viabilityScore !== undefined && (
                                        <div className="text-right">
                                            <span className={cn(
                                                "block text-2xl font-light",
                                                project.viabilityScore >= 70 ? "text-white" : "text-[oklch(0.45_0.01_264)]"
                                            )}>{project.viabilityScore}%</span>
                                        </div>
                                    )}
                                    <div className="px-4 py-2 bg-[oklch(0_0_0)] rounded-lg text-xs font-bold text-[oklch(0.65_0.01_264)] min-w-[120px] text-center uppercase tracking-wider border border-white/5">
                                        {project.classification || "DRAFT"}
                                    </div>
                                    <Button variant="ghost" size="icon" className="h-10 w-10 text-[oklch(0.45_0.01_264)] hover:text-white rounded-full">
                                        <MoreVertical className="w-5 h-5" />
                                    </Button>
                                    <ChevronRight className="w-6 h-6 text-[oklch(0.45_0.01_264)] group-hover:text-white transition-colors" />
                                </div>
                            </Link>
                        ))}
                    </div>
                )}
            </main>
        </div>
    );
}

